class Solution {
    public String countOfAtoms(String formula) {
        int n = formula.length();
        int i = 0;
        Map<String, Integer> count = parseFormula(formula, i, n);
        StringBuilder res = new StringBuilder();
        List<String> elements = new ArrayList<>(count.keySet());
        Collections.sort(elements);
        for (String element : elements) {
            res.append(element);
            if (count.get(element) > 1) {
                res.append(count.get(element));
            }
        }
        return res.toString();
    }

    private Map<String, Integer> parseFormula(String formula, int i, int n) {
        Map<String, Integer> count = new TreeMap<>();
        while (i < n) {
            char c = formula.charAt(i);
            if (c == '(') {
                int j = i + 1;
                int cnt = 1;
                while (cnt != 0) {
                    if (formula.charAt(j) == '(') cnt++;
                    if (formula.charAt(j) == ')') cnt--;
                    j++;
                }
                Map<String, Integer> tmp = parseFormula(formula, i + 1, j - 1);
                i = j;
                int num = parseNum(formula, i, n);
                i += String.valueOf(num).length();
                for (String key : tmp.keySet()) {
                    count.put(key, count.getOrDefault(key, 0) + tmp.get(key) * num);
                }
            } else if (c == ')') {
                break;
            } else {
                int j = i + 1;
                while (j < n && Character.isLowerCase(formula.charAt(j))) j++;
                String name = formula.substring(i, j);
                int num = parseNum(formula, j, n);
                count.put(name, count.getOrDefault(name, 0) + num);
                i = j + String.valueOf(num).length();
            }
        }
        return count;
    }

    private int parseNum(String formula, int i, int n) {
        if (i >= n || !Character.isDigit(formula.charAt(i))) return 1;
        int j = i;
        while (j < n && Character.isDigit(formula.charAt(j))) j++;
        return Integer.parseInt(formula.substring(i, j));
    }
}
